/* Testowy loader pdf-lib + fontkit oraz eksport PDF dla Kalkulator/test.html. */
(function installPreviewMessagePatch(){
  const oldMessage = 'Generating PDF preview...';
  const newMessage = 'The Machine Canticle is rendering the PDF preview...';
  if (window.__wngPdfPreviewWaitingMessagePatchInstalled) return;
  window.__wngPdfPreviewWaitingMessagePatchInstalled = true;

  const originalOpen = window.open;
  window.open = function patchedWindowOpen(){
    const openedWindow = originalOpen.apply(window, arguments);
    try {
      if (openedWindow && openedWindow.document && typeof openedWindow.document.write === 'function') {
        const originalWrite = openedWindow.document.write.bind(openedWindow.document);
        openedWindow.document.write = function patchedDocumentWrite(markup){
          return originalWrite(typeof markup === 'string' ? markup.replace(oldMessage, newMessage) : markup);
        };
      }
    } catch (_) {}
    return openedWindow;
  };
})();

(function loadDependenciesSynchronously(){
  if (!window.PDFLib) {
    document.write('<script src="https://cdn.jsdelivr.net/npm/pdf-lib@1.17.1/dist/pdf-lib.min.js"><\/script>');
  }
  if (!window.fontkit) {
    document.write('<script src="https://cdn.jsdelivr.net/npm/@pdf-lib/fontkit@1.1.1/dist/fontkit.umd.min.js"><\/script>');
  }
})();

(function installColumnPdfExport(){
  'use strict';
  if (window.__wngColumnPdfExportInstalled) return;
  window.__wngColumnPdfExportInstalled = true;

  const FONT_URL = 'https://cdn.jsdelivr.net/gh/notofonts/noto-fonts@main/hinted/ttf/NotoSans/NotoSans-Regular.ttf';
  const ATTRIBUTES = ['S', 'Wt', 'Zr', 'I', 'SW', 'Int', 'Ogd', 'Speed'];
  const SKILLS = [
    ['analysis', 'Int', 'Analiza', 'AnalizaSuma'],
    ['athletics', 'S', 'Atletyka', 'AtletykaSuma'],
    ['awareness', 'Int', 'Czujność', 'CzujnośćSuma'],
    ['leadership', 'SW', 'Dowodzenie', 'DowodzenieSuma'],
    ['insight', 'Ogd', 'Intuicja', 'IntuicjaSuma'],
    ['tech', 'Int', 'Technologia', 'TechnologiaSuma'],
    ['medicae', 'Int', 'Medycyna', 'MedycynaSuma'],
    ['psychicMastery', 'SW', 'Psionika', 'PsionikaSuma'],
    ['deception', 'Ogd', 'Oszukiwanie', 'OszukiwanieSuma'],
    ['persuasion', 'Ogd', 'Perswazja', 'PerswazjaSuma'],
    ['pilot', 'Zr', 'Pilotaż', 'PilotażSuma'],
    ['cunning', 'Ogd', 'Przebiegłość', 'PrzebiegłośćSuma'],
    ['survival', 'SW', 'Przetrwanie', 'PrzetrwanieSuma'],
    ['stealth', 'Zr', 'Ukrywanie się', 'Ukrywanie sięSuma'],
    ['ballisticSkill', 'Zr', 'Umiejętności strzeleckie', 'Umiejętności StrzeleckieSuma'],
    ['weaponSkill', 'I', 'Walka Wręcz', 'Walka WręczSuma'],
    ['scholar', 'Int', 'Wiedza ogólna', 'Wiedza ogólnaSuma'],
    ['intimidation', 'SW', 'Zastraszanie', 'ZastraszanieSuma']
  ].map(([key, attr, pdf, sum]) => ({ key, attr, pdf, sum }));

  const SIZE_DEFENCE_BONUS = { Malutki: 2, Mały: 1, Średni: 0, Duży: 0, Ogromny: 0, Monstrualny: 0 };
  const CORRUPTION_SLOTS = Array.from({ length: 25 }, (_, i) => `Check Box ${i + 1}`);
  const CORRUPTION_LEVEL_SLOTS = ['Check Box 26', 'Check Box 27', 'Check Box 28', 'Check Box 29', 'Check Box 30'];
  const ABILITY_FIELD_NAMES = Array.from({ length: 8 }, (_, i) => `Zdolności i talenty ${i + 1}`);

  const COLUMN_AREAS = {
    abilitiesAndTalents: {
      pageIndex: 1, x: 40, y: 578, width: 530, height: 118,
      minColumns: 2, maxColumns: 4, maxFontSize: 10, minFontSize: 5,
      label: 'Zdolności i Talenty'
    },
    notes: {
      pageIndex: 1, x: 25, y: 40, width: 410, height: 135,
      minColumns: 2, maxColumns: 4, maxFontSize: 10, minFontSize: 5,
      label: 'Notatki'
    },
    background: {
      pageIndex: 0, x: 467, y: 623, width: 109, height: 39,
      minColumns: 1, maxColumns: 3, maxFontSize: 8, minFontSize: 4,
      label: 'Przeszłość'
    }
  };

  const KEYWORDS_AREA = {
    pageIndex: 0,
    firstField: 'Słowa Kluczowe',
    secondField: 'Słowa Kluczowe 2',
    x: 275,
    firstY: 624,
    secondY: 611,
    width: 140,
    height: 13,
    maxFontSize: 10,
    minFontSize: 4
  };

  const $ = id => document.getElementById(id);
  const toInt = (value, fallback) => {
    const number = parseInt(value, 10);
    return Number.isFinite(number) ? number : fallback;
  };
  const clamp = (value, min, max) => Math.max(min, Math.min(max, value));
  const minOne = value => Math.max(1, Math.ceil(Number(value) || 0));
  const minZero = value => Math.max(0, Math.ceil(Number(value) || 0));
  const pad2 = value => String(value).padStart(2, '0');
  const buildPdfFileName = languageCode => {
    const date = new Date();
    return `${languageCode}-${date.getFullYear()}-${pad2(date.getMonth() + 1)}-${pad2(date.getDate())}-${pad2(date.getHours())}${pad2(date.getMinutes())}.pdf`;
  };
  const escapeHtml = text => String(text || '').replace(/[&<>"']/g, character => ({
    '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#039;'
  })[character]);

  function setPdfLog(message, level){
    const element = $('pdfLogMessage');
    if (!element) return;
    element.textContent = message || 'No PDF messages.';
    element.classList.toggle('is-error', level === 'error');
  }

  function showPreviewError(previewWindow, message){
    if (!previewWindow || previewWindow.closed) return;
    previewWindow.document.open();
    previewWindow.document.write(`<!doctype html><html><head><meta charset="utf-8"><title>PDF Preview Error</title></head><body style="margin:24px;background:#000;color:#ffdada;font-family:Consolas,monospace;white-space:pre-wrap;">${escapeHtml(message)}</body></html>`);
    previewWindow.document.close();
  }

  function getAttributes(){
    const result = {};
    ATTRIBUTES.forEach(key => {
      const input = $(`attr_${key}`);
      result[key] = input ? clamp(toInt(input.value, key === 'Speed' ? 6 : 1), 1, 12) : (key === 'Speed' ? 6 : 1);
    });
    return result;
  }

  function getSkills(){
    const result = {};
    SKILLS.forEach(skill => {
      const input = $(`skill_${skill.key}`);
      result[skill.key] = input ? clamp(toInt(input.value, 0), 0, 8) : 0;
    });
    return result;
  }

  function getTalents(){
    return Array.from(document.querySelectorAll('[id^="talent_name_"]')).map(textarea => {
      const index = textarea.id.replace('talent_name_', '');
      const costInput = $(`talent_cost_${index}`);
      return { name: textarea.value || '', cost: costInput ? Math.max(0, toInt(costInput.value, 0)) : 0 };
    });
  }

  function getSpecialRules(){
    return Array.from(document.querySelectorAll('#specialRulesTable tr[data-rule-index]')).map(row => {
      const index = row.dataset.ruleIndex;
      return {
        type: $(`rule_type_${index}`)?.value || 'other',
        name: $(`rule_name_${index}`)?.value || '',
        target: $(`rule_target_${index}`)?.value || 'none',
        value: toInt($(`rule_value_${index}`)?.value, 0)
      };
    });
  }

  function compactEntry(text){
    return String(text || '')
      .split('\n')
      .map(line => line.trim())
      .filter(Boolean)
      .join(' / ');
  }

  function buildTextEntries(rules){
    const entries = { abilitiesAndTalents: [], notes: [], background: [] };

    getTalents().forEach(talent => {
      const entry = compactEntry(talent.name);
      if (entry) entries.abilitiesAndTalents.push(entry);
    });

    rules.forEach(rule => {
      const entry = compactEntry(rule.name);
      if (!entry) return;

      if (rule.type === 'backgroundBonus') {
        entries.background.push(entry);
      } else if (rule.type === 'archetypeAbility' && rule.target === 'none') {
        entries.abilitiesAndTalents.push(entry);
      } else {
        entries.notes.push(entry);
      }
    });

    return entries;
  }

  function computeData(){
    const attrs = getAttributes();
    const skills = getSkills();
    const skillTotals = {};
    SKILLS.forEach(skill => {
      skillTotals[skill.key] = (skills[skill.key] || 0) + (attrs[skill.attr] || 0);
    });

    const character = {
      gameTier: clamp(toInt($('character_gameTier')?.value, 1), 1, 5),
      speciesName: ($('character_speciesName')?.value || '').trim(),
      size: $('character_size')?.value || 'Średni',
      factionName: ($('character_factionName')?.value || '').trim(),
      archetypeName: ($('character_archetypeName')?.value || '').trim(),
      keywords: ($('character_keywords')?.value || '').trim()
    };

    const rules = getSpecialRules();
    const bonus = {};
    rules.forEach(rule => {
      if (rule.target && rule.target !== 'none') bonus[rule.target] = (bonus[rule.target] || 0) + (Number(rule.value) || 0);
    });

    const influenceBase = $('derived_influenceAttribute')?.value || 'Ogd';
    const corruptionBase = toInt($('derived_corruptionBase')?.value, 0);
    const raw = {
      woundsMax: attrs.Wt + 2 * character.gameTier + (bonus.woundsMax || 0),
      shock: attrs.SW + character.gameTier + (bonus.shock || 0),
      determination: attrs.Wt + (bonus.determination || 0),
      defence: attrs.I - 1 + (SIZE_DEFENCE_BONUS[character.size] || 0) + (bonus.defence || 0),
      resilience: attrs.Wt + 1 + (bonus.resilience || 0),
      resolve: attrs.SW + (bonus.resolve || 0),
      conviction: attrs.SW - 1 + (bonus.conviction || 0),
      influence: (attrs[influenceBase] || attrs.Ogd) - 1 + (bonus.influence || 0),
      wealth: character.gameTier + (bonus.wealth || 0),
      corruption: corruptionBase + (bonus.corruption || 0),
      speed: attrs.Speed + (bonus.speed || 0),
      passiveAwareness: Math.ceil((skillTotals.awareness || 0) / 2)
    };

    return {
      attrs,
      skills,
      skillTotals,
      character,
      rules,
      entries: buildTextEntries(rules),
      values: {
        woundsMax: minOne(raw.woundsMax),
        shock: minOne(raw.shock),
        determination: minOne(raw.determination),
        defence: minOne(raw.defence),
        resilience: minOne(raw.resilience),
        resolve: minOne(raw.resolve),
        conviction: minOne(raw.conviction),
        influence: minOne(raw.influence),
        wealth: minOne(raw.wealth),
        corruption: minZero(raw.corruption),
        speed: minOne(raw.speed),
        passiveAwareness: minOne(raw.passiveAwareness)
      }
    };
  }

  function setTextField(form, name, value, font, warnings, skipBlank = true){
    const text = String(value ?? '');
    if (skipBlank && !text.trim()) return;

    try {
      const field = form.getTextField(name);
      field.setText(text);
      const length = text.length;
      const size = length > 900 ? 5 : length > 650 ? 6 : length > 420 ? 7 : length > 240 ? 8 : 10;
      try { field.setFontSize(size); } catch (_) {}
      try { field.updateAppearances(font); } catch (error) {
        warnings.push(`Could not set font for field ${name}: ${error.message}`);
      }
    } catch (_) {
      warnings.push(`Missing PDF field: ${name}`);
    }
  }

  function clearAndRemoveTextField(form, name, font){
    try {
      const field = form.getTextField(name);
      try { field.setText(''); } catch (_) {}
      try { field.updateAppearances(font); } catch (_) {}
      try { form.removeField(field); } catch (_) {}
    } catch (_) {}
  }

  function setCheckBox(form, name, checked, warnings){
    try {
      const field = form.getCheckBox(name);
      checked ? field.check() : field.uncheck();
      field.updateAppearances();
    } catch (_) {
      warnings.push(`Missing PDF checkbox: ${name}`);
    }
  }

  async function loadPolishFont(pdfDoc){
    if (!window.fontkit) throw new Error('Missing fontkit. Check Kalkulator/vendor/pdf-lib.min.js.');
    pdfDoc.registerFontkit(window.fontkit);
    const response = await fetch(FONT_URL);
    if (!response.ok) throw new Error('Could not fetch Noto Sans Regular font.');
    return pdfDoc.embedFont(await response.arrayBuffer(), { subset: false });
  }

  function wrapTextToWidth(text, font, fontSize, maxWidth, prefix = '', hangingPrefix = ''){
    const words = String(text || '').split(/\s+/).filter(Boolean);
    const lines = [];
    let line = prefix;
    const width = value => font.widthOfTextAtSize(value, fontSize);

    const flush = () => {
      if (line.trim()) lines.push(line);
      line = hangingPrefix;
    };

    words.forEach(word => {
      const candidate = line.trim() ? `${line} ${word}` : `${line}${word}`;
      if (width(candidate) <= maxWidth) {
        line = candidate;
        return;
      }

      if (line.trim()) flush();

      if (width(`${hangingPrefix}${word}`) <= maxWidth) {
        line = `${hangingPrefix}${word}`;
        return;
      }

      let chunk = '';
      for (const character of word) {
        if (chunk && width(`${hangingPrefix}${chunk}${character}`) > maxWidth) {
          lines.push(`${hangingPrefix}${chunk}`);
          chunk = character;
        } else {
          chunk += character;
        }
      }
      line = `${hangingPrefix}${chunk}`;
    });

    if (line.trim()) lines.push(line);
    return lines;
  }

  function layoutColumnText(entries, area, font){
    const gutter = area.gutter ?? 10;
    const normalized = entries.map(compactEntry).filter(Boolean);

    for (let columns = area.minColumns; columns <= area.maxColumns; columns++) {
      for (let fontSize = area.maxFontSize; fontSize >= area.minFontSize; fontSize--) {
        const colWidth = (area.width - gutter * (columns - 1)) / columns;
        const lineHeight = fontSize * 1.18;
        const linesPerColumn = Math.floor(area.height / lineHeight);
        const lines = normalized.flatMap(entry => wrapTextToWidth(entry, font, fontSize, colWidth, '- ', '  '));

        if (lines.length <= linesPerColumn * columns) {
          return { columns, fontSize, lineHeight, linesPerColumn, colWidth, lines, omitted: 0 };
        }
      }
    }

    const columns = area.maxColumns;
    const fontSize = area.minFontSize;
    const colWidth = (area.width - gutter * (columns - 1)) / columns;
    const lineHeight = fontSize * 1.18;
    const linesPerColumn = Math.floor(area.height / lineHeight);
    const allLines = normalized.flatMap(entry => wrapTextToWidth(entry, font, fontSize, colWidth, '- ', '  '));
    const capacity = linesPerColumn * columns;

    return {
      columns, fontSize, lineHeight, linesPerColumn, colWidth,
      lines: allLines.slice(0, capacity),
      omitted: Math.max(0, allLines.length - capacity)
    };
  }

  function drawColumnText(pdfDoc, entries, area, font, warnings){
    if (!entries.length) return;
    const page = pdfDoc.getPages()[area.pageIndex];

    if (!page) {
      warnings.push(`${area.label}: missing PDF page ${area.pageIndex}.`);
      return;
    }

    const layout = layoutColumnText(entries, area, font);
    const gutter = area.gutter ?? 10;
    const color = window.PDFLib.rgb(0, 0, 0);

    layout.lines.forEach((line, index) => {
      const column = Math.floor(index / layout.linesPerColumn);
      const row = index % layout.linesPerColumn;
      const x = area.x + column * (layout.colWidth + gutter);
      const y = area.y + area.height - layout.fontSize - row * layout.lineHeight;
      page.drawText(line, { x, y, size: layout.fontSize, font, color });
    });

    if (layout.omitted) {
      warnings.push(`${area.label}: tekst przekracza dostępny obszar. Pominięto ${layout.omitted} linii po automatycznym doborze ${layout.columns} kolumn i fontu ${layout.fontSize}.`);
    }
  }

  function fitKeywords(text, font, warnings){
    const normalized = compactEntry(text).replace(/\s*\/\s*/g, ', ');
    if (!normalized) return { lines: [], fontSize: KEYWORDS_AREA.maxFontSize };

    for (let fontSize = KEYWORDS_AREA.maxFontSize; fontSize >= KEYWORDS_AREA.minFontSize; fontSize--) {
      const lines = wrapTextToWidth(normalized, font, fontSize, KEYWORDS_AREA.width);
      if (lines.length <= 2) return { lines, fontSize };
    }

    const fontSize = KEYWORDS_AREA.minFontSize;
    const lines = wrapTextToWidth(normalized, font, fontSize, KEYWORDS_AREA.width);
    warnings.push('Słowa Kluczowe: tekst przekracza dwie linie. Nadmiar został pominięty.');
    return { lines: lines.slice(0, 2), fontSize };
  }

  function createKeywordSecondField(form, page, font, text, fontSize){
    if (!text) return;

    try {
      const existing = form.getTextField(KEYWORDS_AREA.secondField);
      existing.setText(text);
      existing.setFontSize(fontSize);
      existing.updateAppearances(font);
      return;
    } catch (_) {}

    const field = form.createTextField(KEYWORDS_AREA.secondField);
    field.setText(text);
    field.setFontSize(fontSize);
    field.addToPage(page, {
      x: KEYWORDS_AREA.x,
      y: KEYWORDS_AREA.secondY,
      width: KEYWORDS_AREA.width,
      height: KEYWORDS_AREA.height,
      borderWidth: 0,
      textColor: window.PDFLib.rgb(0, 0, 0),
      font
    });
    field.updateAppearances(font);
  }

  function setKeywordsFields(pdfDoc, form, text, font, warnings){
    const page = pdfDoc.getPages()[KEYWORDS_AREA.pageIndex];
    const fitted = fitKeywords(text, font, warnings);

    try {
      const firstField = form.getTextField(KEYWORDS_AREA.firstField);
      firstField.setText(fitted.lines[0] || '');
      firstField.setFontSize(fitted.fontSize);
      firstField.updateAppearances(font);
    } catch (_) {
      warnings.push(`Missing PDF field: ${KEYWORDS_AREA.firstField}`);
    }

    if (page && fitted.lines[1]) {
      createKeywordSecondField(form, page, font, fitted.lines[1], fitted.fontSize);
    }
  }

  function removeLargeTextFields(form, font){
    ABILITY_FIELD_NAMES.forEach(name => clearAndRemoveTextField(form, name, font));
    clearAndRemoveTextField(form, 'Notatki 1', font);
    clearAndRemoveTextField(form, 'Przeszłość', font);
  }

  function fillStandardFields(pdfDoc, form, data, font, warnings){
    const { character, values } = data;

    setTextField(form, 'Poziom', character.gameTier, font, warnings, false);
    setTextField(form, 'Gatunek', character.speciesName, font, warnings);
    setTextField(form, 'Archetyp', character.archetypeName, font, warnings);
    setTextField(form, 'Frakcja', character.factionName, font, warnings);
    setKeywordsFields(pdfDoc, form, character.keywords, font, warnings);
    setTextField(form, 'Rozmiar', character.size, font, warnings, false);
    setTextField(form, 'Szybkość', values.speed, font, warnings, false);

    ['S', 'Wt', 'Zr', 'I', 'SW', 'Int', 'Ogd'].forEach(key => {
      setTextField(form, key, data.attrs[key], font, warnings, false);
    });

    SKILLS.forEach(skill => {
      setTextField(form, skill.pdf, data.skills[skill.key], font, warnings, false);
      setTextField(form, skill.sum, data.skillTotals[skill.key], font, warnings, false);
    });

    [
      ['Upór', values.resolve],
      ['Odwaga', values.conviction],
      ['Obrona', values.defence],
      ['Bazowa Odporność', values.resilience],
      ['Maksymalna Żywotność', values.woundsMax],
      ['Odporność Psychiczna', values.shock],
      ['Determinacja', values.determination],
      ['Wpływy', values.influence],
      ['Majątek', values.wealth],
      ['Pasywna Czujność', values.passiveAwareness]
    ].forEach(([name, value]) => setTextField(form, name, value, font, warnings, false));

    CORRUPTION_SLOTS.forEach((name, index) => setCheckBox(form, name, index < values.corruption, warnings));
    const levelMarks = Math.max(0, Math.min(4, Math.ceil(((Number(values.corruption) || 0) - 5) / 5)));
    CORRUPTION_LEVEL_SLOTS.forEach((name, index) => setCheckBox(form, name, index < levelMarks, warnings));
  }

  function openPreviewWindow(){
    const previewWindow = window.open('', '_blank');
    if (previewWindow) {
      previewWindow.document.write('<!doctype html><html><head><meta charset="utf-8"><title>Generating PDF...</title></head><body style="margin:24px;background:#000;color:#9cf09c;font-family:Consolas,monospace;">The Machine Canticle is rendering the PDF preview...</body></html>');
      previewWindow.document.close();
    }
    return previewWindow;
  }

  async function exportColumnPdf(previewWindow){
    const warnings = [];

    try {
      if (!window.PDFLib?.PDFDocument) throw new Error('Missing PDFLib. Add local file Kalkulator/vendor/pdf-lib.min.js.');

      const data = computeData();
      const response = await fetch('./pdf/pl.pdf');
      if (!response.ok) throw new Error('Could not fetch ./pdf/pl.pdf');

      const pdfDoc = await window.PDFLib.PDFDocument.load(await response.arrayBuffer());
      const font = await loadPolishFont(pdfDoc);
      const form = pdfDoc.getForm();

      fillStandardFields(pdfDoc, form, data, font, warnings);
      removeLargeTextFields(form, font);
      drawColumnText(pdfDoc, data.entries.abilitiesAndTalents, COLUMN_AREAS.abilitiesAndTalents, font, warnings);
      drawColumnText(pdfDoc, data.entries.notes, COLUMN_AREAS.notes, font, warnings);
      drawColumnText(pdfDoc, data.entries.background, COLUMN_AREAS.background, font, warnings);

      const output = await pdfDoc.save({ updateFieldAppearances: false });
      const fileName = buildPdfFileName('PL');
      const pdfFile = window.File
        ? new File([output], fileName, { type: 'application/pdf' })
        : new Blob([output], { type: 'application/pdf' });
      const url = URL.createObjectURL(pdfFile);

      if (previewWindow && !previewWindow.closed) {
        previewWindow.document.title = fileName;
        previewWindow.location.replace(url);
      } else {
        const opened = window.open(url, '_blank');
        if (!opened) warnings.push('PDF generated, but the browser blocked the preview window.');
      }

      setTimeout(() => URL.revokeObjectURL(url), 300000);
      setPdfLog(
        warnings.length ? warnings.join('\n') : 'PDF generated with dynamic layout for Zdolności i Talenty, Notatki, Przeszłość and Słowa Kluczowe.',
        warnings.length ? 'warn' : 'ok'
      );
    } catch (error) {
      console.error(error);
      const message = error.stack || error.message;
      setPdfLog(message, 'error');
      showPreviewError(previewWindow, message);
    }
  }

  document.addEventListener('click', event => {
    const button = event.target?.closest?.('#exportCharacterPdfButton');
    if (!button) return;

    event.preventDefault();
    event.stopPropagation();
    event.stopImmediatePropagation?.();

    exportColumnPdf(openPreviewWindow());
  }, true);
})();
